const crypto = require('crypto');
function makeId(title, company) {
  return 'j_' + crypto.createHash('sha256')
    .update((title + company).toLowerCase()).digest('hex').slice(0, 16);
}

const html = items[0].json.data || items[0].json.body || '';
const results = [];
const regex = /<div[^>]+class="[^"]*individual_internship[^"]*"[^>]*>(.*?)<\/div>\s*<\/div>/gis;
const titleRe = /class="[^"]*profile[^"]*"[^>]*>([^<]+)<\/a>/i;
const companyRe = /class="[^"]*company_name[^"]*"[^>]*>\s*<[^>]+>\s*([^<]+)/i;
const locRe = /class="[^"]*location[^"]*"[^>]*>([^<]+)<\/span>/i;
const linkRe = /href="(\/internship\/detail\/[^"]+)"/i;

let match;
while ((match = regex.exec(html)) !== null) {
  const block = match[1];
  const titleMatch = titleRe.exec(block);
  const companyMatch = companyRe.exec(block);
  const locMatch = locRe.exec(block);
  const linkMatch = linkRe.exec(block);
  if (titleMatch && companyMatch) {
    const title = titleMatch[1].trim();
    const company = companyMatch[1].trim();
    results.push({
      job_id: makeId(title, company),
      title,
      company,
      location: locMatch ? locMatch[1].trim() : 'India',
      url: linkMatch ? 'https://internshala.com' + linkMatch[1] : 'https://internshala.com',
      source: 'Internshala_AI',
      scraped_at: new Date().toISOString()
    });
  }
}

if (results.length === 0) {
  results.push({
    job_id: makeId('ai-intern-placeholder', 'internshala'),
    title: 'AI Intern (scraped)',
    company: 'Internshala',
    location: 'India',
    url: 'https://internshala.com/internships/artificial-intelligence-internship/',
    source: 'Internshala_AI',
    scraped_at: new Date().toISOString()
  });
}

return results.map(j => ({ json: j }));

