const crypto = require('crypto');
function makeId(title, company) {
  return 'j_' + crypto.createHash('sha256')
    .update((title + company).toLowerCase()).digest('hex').slice(0, 16);
}

const raw = items[0].json;
const list = Array.isArray(raw) ? raw : [];
const results = [];

for (const job of list) {
  if (!job || !job.position) continue;
  const title = (job.position || '').trim();
  const company = (job.company || 'Unknown').trim();
  if (!title) continue;
  results.push({
    job_id: makeId(title, company),
    title,
    company,
    location: job.location || 'Remote',
    url: job.url || ('https://remoteok.com/jobs/' + (job.id || '')),
    source: 'RemoteOK',
    description: (job.description || '').slice(0, 500),
    scraped_at: new Date().toISOString()
  });
}

if (results.length === 0) {
  return [{ json: { _sentinel: true, source: 'RemoteOK' } }];
}

return results.map(j => ({ json: j }));

const crypto = require('crypto');
function makeId(title, company) {
  return 'j_' + crypto.createHash('sha256')
    .update((title + company).toLowerCase()).digest('hex').slice(0, 16);
}

const ids = items[0].json;
const slice = Array.isArray(ids) ? ids.slice(0, 20) : [];
const results = [];

for (const id of slice) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://hacker-news.firebaseio.com/v0/item/${id}.json`
    });
    if (!resp || resp.type !== 'job') continue;
    const rawTitle = resp.title || '';
    const lower = rawTitle.toLowerCase();
    if (!lower.includes('ml') && !lower.includes('machine learning') &&
        !lower.includes('ai') && !lower.includes('artificial intelligence') &&
        !lower.includes('deep learning') && !lower.includes('nlp') &&
        !lower.includes('data science')) continue;
    const urlMatch = rawTitle.match(/\(([^)]+)\)$/);
    const company = urlMatch ? urlMatch[1] : 'HackerNews Job';
    const title = rawTitle.replace(/\s*\([^)]*\)\s*$/, '').trim();
    results.push({
      job_id: makeId(title, company),
      title,
      company,
      location: 'Remote/Various',
      url: resp.url || `https://news.ycombinator.com/item?id=${id}`,
      source: 'HackerNews',
      description: (resp.text || '').replace(/<[^>]*>/g, '').slice(0, 500),
      scraped_at: new Date().toISOString()
    });
  } catch (e) { /* skip */ }
}

if (results.length === 0) {
  return [{ json: { _sentinel: true, source: 'HackerNews' } }];
}

return results.map(j => ({ json: j }));

// Separate github state item from real job items by field presence
const allItems = items;

let githubItem = null;
let newJobs = [];

for (const i of allItems) {
  if (i.json.sha !== undefined && i.json.content !== undefined) {
    githubItem = i.json;
  } else if (i.json.source !== undefined && !i.json._sentinel) {
    newJobs.push(i.json);
  }
}

// Parse existing jobs from GitHub base64 content
let existingJobs = [];
let fileSha = null;

if (githubItem) {
  fileSha = githubItem.sha;
  try {
    const decoded = Buffer.from(githubItem.content, 'base64').toString('utf8');
    existingJobs = JSON.parse(decoded);
    if (!Array.isArray(existingJobs)) existingJobs = [];
  } catch (e) {
    existingJobs = [];
  }
}

const existingIds = new Set(existingJobs.map(j => j.job_id));

const freshJobs = newJobs.filter(j => j.job_id && !existingIds.has(j.job_id));

return [{
  json: {
    fresh_jobs: freshJobs,
    existing_jobs: existingJobs,
    file_sha: fileSha,
    fresh_count: freshJobs.length
  }
}];

const data = items[0].json;
const freshJobs = data.fresh_jobs;
const existingJobs = data.existing_jobs;
const fileSha = data.file_sha;

const jobList = freshJobs.map((j, i) => `[${i}] ${j.title} at ${j.company} (${j.source})`).join('\n');

const prompt = `You are an AI job relevance scorer for a candidate with this profile:
- B.Tech AI & Machine Learning student (CGPA 8.35, graduating Sep 2026)
- Projects: GPT-style transformer (EMERALD), Fake News Detection, AI Crop Prediction, Binance Trading Bot
- Skills: Python, PyTorch, TensorFlow, Scikit-learn, Flask, FastAPI, NLTK, SpaCy, Pandas, NumPy, Flutter
- Certifications: NPTEL Elite — Introduction to Large Language Models

Score each job below from 0-100 for relevance to this candidate. Return ONLY a JSON array of objects with fields: index (integer), score (integer 0-100), reason (one sentence).

Jobs to score:
${jobList}

Return only the JSON array, no other text.`;

return [{
  json: {
    fresh_jobs: freshJobs,
    existing_jobs: existingJobs,
    file_sha: fileSha,
    groq_request: {
      model: 'openai/gpt-oss-120b',
      messages: [
        { role: 'system', content: 'You are a precise job relevance scorer. Return only valid JSON.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.2,
      max_tokens: 2048
    }
  }
}];

const groqResp = items[0].json;
const originalData = $('Build Groq Score Req').first().json;

const freshJobs = originalData.fresh_jobs;
const existingJobs = originalData.existing_jobs;
const fileSha = originalData.file_sha;

let scores = [];
try {
  const content = groqResp.choices[0].message.content;
  const jsonMatch = content.match(/\[.*\]/s);
  scores = jsonMatch ? JSON.parse(jsonMatch[0]) : [];
} catch (e) {
  scores = [];
}

const scoreMap = {};
for (const s of scores) {
  if (s.index !== undefined) {
    scoreMap[s.index] = { score: s.score || 0, reason: s.reason || '' };
  }
}

const scoredFresh = freshJobs.map((j, i) => ({
  ...j,
  relevance_score: scoreMap[i] ? scoreMap[i].score : 0,
  score_reason: scoreMap[i] ? scoreMap[i].reason : 'Not scored',
  scored_at: new Date().toISOString()
}));

const allJobs = [...existingJobs, ...scoredFresh];
allJobs.sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0));

const content = JSON.stringify(allJobs, null, 2);
const contentB64 = Buffer.from(content).toString('base64');

const payload = {
  message: `Update jobs.json — ${scoredFresh.length} new jobs added on ${new Date().toISOString()}`,
  content: contentB64,
  branch: 'state'
};

if (fileSha) {
  payload.sha = fileSha;
}

return [{
  json: {
    github_payload: payload,
    job_count: allJobs.length,
    new_count: scoredFresh.length
  }
}];
